mapper.select:
SELECT crm.CNSG_REQS_ID , crm.REQS_INTT_ID , crm.CNSG_PTRN_CD , ccd_ptrn.COM_CD_NM AS CNSG_PTRN_NM , crm.CNSG_REQS_TTL , crm.CNSG_REQS_CON , crm.CNSG_RPLY_CON , crm.CNSG_STTS_CD , ccd_stts.COM_CD_NM AS CNSG_STTS_NM
, crm.RGSN_USER_ID , crm.RGSN_TS , crm.AMNN_USER_ID , crm.AMNN_TS
, crm.RPLY_MNGR_ID , crm.RPLY_TS FROM TB_BOX_IVT_CNSG_REQS_M crm LEFT JOIN TB_BOX_IVT_COM_CD_D ccd_ptrn ON crm.CNSG_PTRN_CD = ccd_ptrn.COM_CD_ID LEFT JOIN TB_BOX_IVT_COM_CD_D ccd_stts ON crm.CNSG_STTS_CD = ccd_stts.COM_CD_ID WHERE crm.CNSG_REQS_ID = #{cnsgReqsId}

mapper.insert:
INSERT INTO TB_BOX_IVT_CNSG_REQS_M
(
    CNSG_REQS_ID
    , REQS_INTT_ID
    , CNSG_PTRN_CD
    , CNSG_REQS_TTL
    , CNSG_REQS_CON
    , CNSG_STTS_CD
    , RGSN_USER_ID
    , RGSN_TS
    , AMNN_USER_ID
    , AMNN_TS

    , RGSN_USER_NM
)
VALUES
(
    #{cnsgReqsId}
    , #{reqsInttId}
    , #{cnsgPtrnCd}
    , #{cnsgReqsTtl}
    , #{cnsgReqsCon}
    , #{cnsgSttsCd}
    , #{rgsnUserId}
    , CURRENT_TIMESTAMP
    , #{amnnUserId}
    , CURRENT_TIMESTAMP

    , #{rgsnUserNm}
)

mapper.update:
UPDATE
    TB_BOX_IVT_CNSG_REQS_M
SET
    CNSG_PTRN_CD  = #{cnsgPtrnCd}
    , CNSG_REQS_TTL = #{cnsgReqsTtl}
    , CNSG_REQS_CON = #{cnsgReqsCon}
    , AMNN_USER_ID  = #{amnnUserId}
    , AMNN_TS       = CURRENT_TIMESTAMP
WHERE
    CNSG_REQS_ID = #{cnsgReqsId} AND REQS_INTT_ID = #{reqsInttId}

UPDATE
    TB_BOX_IVT_CNSG_REQS_M
SET
    CNSG_STTS_CD    = #{cnsgSttsCd}
    , AMNN_USER_ID  = #{amnnUserId}
    , AMNN_TS       = CURRENT_TIMESTAMP
WHERE
    CNSG_REQS_ID = #{cnsgReqsId} AND REQS_INTT_ID = #{reqsInttId}
